#include <algorithm>
#include <string>

class Solution {
public:
    std::string largestMerge(std::string word1, std::string word2) {
        std::string result = "";
        std::string temp1 = word1;
        std::string temp2 = word2;

        while (temp1.length() > 0 || temp2.length() > 0) {
            if (temp1.length() > temp2.length()) {
                result = temp1;
                temp1.erase();
            } else {
                result = temp2;
                temp2.erase();
            }

            if (result.length() > temp1.length()) {
                temp1 = temp1 + temp2;
            } else {
                temp2 = temp2 + temp1;
            }
        }

        return result;
    }
};
```

